def final_occupied_positions(nums, moveFrom, moveTo):
    # Count marbles at each position
    from collections import Counter
    pos_count = Counter(nums)

    for frm, to in zip(moveFrom, moveTo):
        if frm != to:
            count = pos_count[frm]
            pos_count[to] += count
            del pos_count[frm]

    return sorted(pos_count.keys())
